// Contenu PDF des brochures partenaires, encodé en base64, généré une seule
// fois à partir du rendu réel des brochures (brochure_offre_speciale.html
// = Offre Free, brochure_offre_standard.html = Offre Participation), converties
// via Playwright/Chromium pour préserver fidèlement leur mise en forme (thème
// sombre, dégradés, images). Le lien "Devenir partenaire", relatif dans le
// HTML source, a été réécrit en URL absolue
// (https://haltiss-simulateur.netlify.app/questionnaire_onboarding_haltiss.html)
// avant conversion, pour qu'il fonctionne une fois le PDF ouvert par le
// prestataire (un lien relatif n'a pas de sens hors du contexte du site).
//
// Embarqué ici en base64 plutôt que rendu à la volée : pas besoin de faire
// tourner un navigateur headless dans la fonction Netlify (fragile et coûteux
// en environnement serverless), et le contenu des brochures ne change pas
// d'un envoi à l'autre.
//
// Pour régénérer après modification d'une brochure ou changement de domaine :
// reconvertir le fichier source en PDF (Playwright page.pdf() avec
// printBackground: true, après avoir réécrit le lien en URL absolue), puis
// remplacer la constante correspondante ci-dessous par le nouveau base64.

exports.OFFRE_FREE_PDF_B64 = '';
exports.OFFRE_PARTICIPATION_PDF_B64 = '';
